var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRIEST_NPC_HARMONY_NULL","text":{"KOREA":"태양이 사라지고. 또다시 마물이 들끓기 시작했으니.","JPN":"太陽が消え、再び魔物が暴れ出した。","ENG":"The sun has disappeared, and monsters have started to take over again.","TWN":"太陽消失了，怪物又開始肆虐。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRIEST_NPC_HARMONY_NULL","text":{"KOREA":"이는 불경한 어둠 타기리온이 또다시 하늘아래 재림하였음이라.","JPN":"これは不敬な闇、タギリオンが再びこの空の下に再臨したことである。","ENG":"The unholy darkness, Thagirion, has once again been reincarnated.","TWN":"這表示不祥的黑暗塔基里翁再次降臨。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRIEST_NPC_HARMONY_NULL","text":{"KOREA":"그리하여 우리는 연주와 기도를 통해 태양문의 빛을 높이 밝히니…!","JPN":"そして我らは演奏と祈りによって太陽の扉の光を高く照らす……！","ENG":"So let our prayers and performances illuminate the Solar Gates...!","TWN":"於是我們透過演奏與祈禱使太陽門之光再次照耀……！"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRIEST_NPC_HARMONY_NULL","text":{"KOREA":"다시 한번 위대한 정적께서 타기리온을 멸하여 우리를 구원으로 이끄실 것이다!","JPN":"今一度偉大なる静寂によりタギリオンを滅ぼし、我らを救いへと導くであろう！","ENG":"For the Great Silence will defeat Thagirion and bring salvation once again!","TWN":"偉大的寂靜將再次消滅塔基里翁，帶領我們走向救贖！"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아우드라는… 끝내 출정식에 모습을 드러내지 않았군.","JPN":"アウドラは……最後まで出征式に姿を見せなかったのだな。","ENG":"Audra... did not show up at the ceremony of war after all.","TWN":"奧德拉……終究還是沒有在遠征儀式露面。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"실로 안타깝군요.","JPN":"実に残念です。","ENG":"What a shame, indeed.","TWN":"太可惜了。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하께서 마지막 아량을 베푸셨음에도, 그 기대를 배반하다니","JPN":"猊下が最後まで寛容に対応してくださったのに、その期待を裏切るとは。","ENG":"You showed your generosity, and yet she has betrayed your expectations.","TWN":"主教已經給予了最後的寬容，她卻還是背叛了這份心意。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그토록 믿으시던 아이가 제 악단의 귀를 도려내고 도망칠 줄 누가 알았을까요?","JPN":"あんなに信じていた子どもが私の楽団の耳を切り、逃げ出すとは思いもしませんでした。","ENG":"Who would have thought that the child you trusted so much would run away after tearing my orchestra's ears?","TWN":"誰會料到如此信任的孩子會割下樂團的耳朵逃跑？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"정녕 그 아이가… 자신의 누이를 찾기 위해 그런 만행을 저지른 것인가?","JPN":"あの子が……自分の姉を探すためにそのようなことをしたとは誠か？","ENG":"Did the child... commit such brutality all to just find her sister?","TWN":"那孩子……真的是為了尋找自己的姊姊做出了那種事？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이교도를 신뢰하는 것엔 대가가 필요한 법이죠. 지금이라도 교훈을 얻으셨다면 다행입니다.","JPN":"異教徒を信じるには対価が必要なものです。今からでも教訓を得たのであれば幸いでございます。","ENG":"Trusting a pagan always comes with a price. I would be glad if this helped you learn your lesson.","TWN":"這就是信任一個異教徒的代價，希望能從中吸取教訓。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 아이가 도망친 곳이 겨울의 땅이었다면, 분명 이번에도 타기리온과 마주치기 전에 만날 수 있겠지.","JPN":"逃げたのが冬の地であれば、きっと今回もタギリオンと出くわす前に会えるであろう。","ENG":"If she ran to the Gelid Lands, I shall be able to come across her again before encountering Thagirion.","TWN":"如果那孩子逃到了冬境，應該能在她遇到塔基里翁之前找到她。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아직도… 그 아이에 대한 미련을 버리지 못하시는 건가요?","JPN":"まだ……あの子どもに未練がおありですか？","ENG":"Have you... still not let go of your attachment to that child?","TWN":"主教還是……忘不了她？……還是沒有放棄她嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 직접 그 아이를 만나 묻겠다.","JPN":"我が直に会って話を聞こう。","ENG":"I will meet her and ask her myself.","TWN":"我要親自去找她問。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"사정이 있다면 경청할 것이고, 악의가 있었다면 교화를 통해서라도…","JPN":"事情があるなら耳を傾けてやろう。悪意があったのなら教化をしてでも……","ENG":"I will listen if she had a good reason, and if there was any malice...","TWN":"如果有理由，我會聆聽。如果有惡意，我會教化……"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 아이를 구원할 것이다.","JPN":"あの子どもを救う。","ENG":"I will save her through edification.","TWN":"拯救那個孩子。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"……這樣啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그러니, 그전까지 엘리시온의 주민들에겐 그녀가 저지른 일은 비밀로 부탁하마.","JPN":"だから、それまではエリシオンの民にはあの子がしたことは内密に頼む。","ENG":"So until then, I ask you to keep what she did a secret from the residents of Elysion.","TWN":"所以在那之前，那孩子做的事要對艾利森的居民們保密。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하의 뜻이 그러시다면 저는 따를 뿐입니다.","JPN":"猊下の御心がそのようであれば、私はそれに従うまでです。","ENG":"If that is your will, I shall follow, Your Eminence.","TWN":"我遵從主教的意願。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이번에도 부디, 무사히 돌아 오시길.","JPN":"今回もどうか、無事の帰還をお祈りいたします。","ENG":"I will pray that you return home safe this time as well.","TWN":"希望主教這次也平安歸來。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"예하께선 정말 순진하시네요.","JPN":"猊下は本当に純粋ですね。","ENG":"Her Eminence can be so innocent.","TWN":"主教真是天真。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그 점이 매력이라고 생각하지만요.","JPN":"そんなところが魅力的だとは思いますけど。","ENG":"But I think that's a part of her charm.","TWN":"不過這也是她的魅力所在。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"대비해야겠군요.","JPN":"準備を整えておく必要があるわ。","ENG":"We must prepare.","TWN":"我們需要做好準備。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"만약 그 아이가 예하와 함께 살아서 돌아오기라도 한다면, 저희의 연구는 순탄치 못할 테니까요.","JPN":"もしもあの子が猊下とともに生きて戻ってきたら、私たちの研究が邪魔されるはずだから。","ENG":"If that child returns with Her Eminence, it could cause trouble for our research.","TWN":"萬一主教帶著那孩子活著回來，我們的研究就會陷入困境。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"글쎄요.","JPN":"どうでしょうね。","ENG":"Perhaps.","TWN":"是嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"제 생각에 그 아이는 돌아오지 않을 겁니다.","JPN":"私の考えですが、あの子どもは戻らないはずです。","ENG":"But I do not think that child will return.","TWN":"我覺得那孩子不會回來。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그녀의 세상은 이미 무너졌고, 예하께서 자신을 배반했을 거라 굳게 믿고 있으니까요.","JPN":"彼女の世界は既に崩壊しています。猊下が自分を裏切ったと信じているはずですから。","ENG":"Her world has already been crushed, and she firmly believes that Her Eminence has betrayed her.","TWN":"她的世界早已瓦解，她堅信主教背叛了自己。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"왜 그랬던 거야?","JPN":"なんでそんなことをした？","ENG":"Why did you do it?","TWN":"你為什麼這麼做？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"도대체 왜 그렇게 하면서까지… 진실을 묻어두고 두 사람에게 갈등을 만든 거지?","JPN":"一体なんでそこまでして……真実を隠して二人の仲に軋轢を生じさせたんだ？","ENG":"Why did you have to go that far... to bury the truth and cause conflict between the two?","TWN":"你究竟為什麼要做到這個地步……掩蓋真相，在兩個人之間製造矛盾？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 아이 앞에 무릎 꿇고 사죄했다면…","JPN":"その子の前で膝をついて謝罪したのなら……","ENG":"If you had just kneeled in front of that child and begged for forgiveness...","TWN":"如果你跪在孩子面前向她道歉……"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아니 적어도, 에클레시아에게만이라도 사실을 말했다면…!","JPN":"いや、少なくともエクレシアにだけでも真実を話したのならば……！","ENG":"Or rather, if you had at least just told Ecclesia the truth...!","TWN":"或者至少把真相告訴艾可露西亞……！"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"문제는 이렇게까지 커지지 않았을 지도 모르잖아.","JPN":"問題はここまで大きくならなかったかもしれない。","ENG":"It wouldn't have escalated as much.","TWN":"也許問題就不會變得這麼嚴重。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"진실이 모든 갈등을 해결해주지는 않아요.","JPN":"真実がすべての葛藤を解決してくれるのではありません。","ENG":"The truth does not resolve all conflict.","TWN":"真相並不能解決所有衝突。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"종말 앞에서 우리는 모두 죄인일 뿐입니다.","JPN":"終末の前では私たちは皆、罪人に過ぎません。","ENG":"In the face of an inevitable end, we are all sinners.","TWN":"在末日面前，我們都是罪人。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"우리도… 이교도라 불리는 <color=#ffd34c>그들</color>도…","JPN":"私たちも……異教徒と呼ばれる<color=#ffd34c>彼ら</color>も……","ENG":"We... and <color=#ffd34c>those</color> whom we call pagans...","TWN":"被我們稱為……異教徒的<color=#ffd34c>那些人也</color>……"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"살아남기 위해서라면 자잘한 도덕심 따윈 이미 포기할 각오를 했으니까요.","JPN":"生き残るためであれば、些細な道徳心なんてすべて捨てる覚悟をしましたから。","ENG":"have chosen to give up on trivial matters such as morality in order to survive.","TWN":"已經做好了為生存拋棄道德心的覺悟。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"국가를 위해 헌신을 아끼지 않은 레아 슈나이더라면 이해할 거라고 생각했는데요.","JPN":"国のために献身してきたレア・シュナイダーなら理解してくれると思いましたが。","ENG":"I assumed that you, Leah Schneider, would understand, as you have devoted yourself to your country.","TWN":"我認為如果是為國家無私奉獻的蕾亞·修奈德一定能理解。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이해라고…?","JPN":"理解だと……？","ENG":"Understand...?","TWN":"理解……？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇게 돌아온 대가가 무엇인지 알고 있으면서도, 아직 네가 옳았다고 말하고 싶은 거야?","JPN":"その結果、戻ってきた対価が何か知っているくせに、未だに自分が正しかったとでも言いたいの？","ENG":"Knowing the price you have to pay, are you telling me that you still think you're right?","TWN":"你明知道要付出什麼代價，依然覺得自己是對的？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저희는 틀리지 않았어요. 단지, 실패했을 뿐.","JPN":"私たちは間違っていません。ただ、失敗しただけです。","ENG":"We were not wrong. It was merely a failed attempt.","TWN":"我們沒有錯，我們只是失敗了而已。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"두 차례나 죽었어야 할 제가 살아있는 걸 보면… 제 죄악도 인간의 의지 앞에선 사사로운 것일 뿐인 모양이군요.","JPN":"二度も死ぬべきだった私が生きていることを考えると……私の罪も人間の意志の前では個人的なことでしかなかったようですね。","ENG":"Seeing how I am still alive when I should've died twice... It looks like my sins are nothing compared to human will.","TWN":"我本該死兩次的，卻依然活著……可能我的罪惡在人類的面前根本算不上什麼。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"네퀴티아…!","JPN":"ネキティア……！","ENG":"Nequitia...!","TWN":"莉奎蒂亞……！"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"윽…!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐지? 방금 베인 것 같았는데?","JPN":"なに？　今、切られた気がしたのに？","ENG":"Huh? I thought I felt something cut me.","TWN":"怎麼回事？我剛剛明明被砍到了？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"베었어요. 그 요란스럽게 구는 목을 정확히 그은 줄 알았건만…","JPN":"切りました。そのうるさい首を正確に切ったつもりでしたが……","ENG":"I did. I thought I had aimed directly at that loud mouth of yours...","TWN":"是砍到了。不過我以為精准地砍斷了那吵鬧的喉嚨……"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이 거울은 당신의 상을 똑바로 비추지 못하는 것 같군요.","JPN":"この鏡はあなたを正確に映しているわけではなさそうですね。","ENG":"but this mirror cannot seem to accurately reflect your figure.","TWN":"看來這面鏡子並沒有準確照出你的倒影。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신을 통해 저를 투영하기엔, 우린 이미 너무 다른 존재가 된 걸지도 모르겠네요.","JPN":"あなたを通じて私を映すには、私たちはもう異なる存在になったのかもしれません。","ENG":"To project me through you, perhaps we have already become far too different.","TWN":"也許是因為我們變成了截然不同的存在，所以透過你來投影出我的存在。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"거울이라고? 그럼 이 공간이 거울 속이라는 거야?","JPN":"鏡だって？　じゃあこの空間が鏡の中だというの？","ENG":"Mirror? Are you saying that we're inside a mirror?","TWN":"鏡子？這麼說這個空間是鏡子裡？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"스완의 세계에선 그렇게 불렸어요.","JPN":"スワンの世界ではそう呼んでいました。","ENG":"That was what it was called in Swan's world.","TWN":"在史旺的世界裡是這麼叫的。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"<color=#ffd34c>배우</color>가 되길 원하는 지망생들이 자신의 내면과 마주하기 위해 사용되는 일종의 시험 도구였죠.","JPN":"<color=#ffd34c>役者</color>になりたいと思う者たちが自分の内面と向き合うために利用されていた一種の試験道具でした。","ENG":"It was a test tool for aspiring <color=#ffd34c>actors</color> to confront their inner selves.","TWN":"這是一種測試工具，供那些以<color=#ffd34c>演員</color>為目標的練習生面對內心的自我。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그녀의 세계는 진작 타기리온의 손에 사라졌을 텐데, 어째서 생존자인 그녀가 타기리온과 손을 잡은 것인지는 저도 모르겠지만요.","JPN":"彼女の世界は大昔にタギリオンの手によって消えたはずなのに、なぜ生き残りの彼女がタギリオンと手を組んだのかは私にもわかりませんが。","ENG":"Her world was destroyed by Thagirion's hands a long time ago, so I do not understand why she is willing to join forces with her.","TWN":"她的世界早就應該被塔基里翁摧毀了，為什麼她這個倖存者還要和塔基里翁聯手，我實在想不通。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼 스완이… 다른 세계의 생존자라는 건가?","JPN":"ではスワンは……別の世界の生き残りっていうこと？","ENG":"Then Swan... is a survivor from another world?","TWN":"史旺是……來自另一個世界的倖存者？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런데, 왜 이런 사실을 나한테 알려주는 거지?","JPN":"でも、なんでそんなことを私に教えてくれるんだ？","ENG":"But why are you telling me this?","TWN":"但你為什麼要告訴我這些？"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신과 나 사이에 남은 공통점이 있다면, 그건 타기리온을 막고 싶어 한다는 거겠죠.","JPN":"あなたと私の間に共通点が残っているとしたら、それはタギリオンを止めたいという想いでしょうね。","ENG":"If you and I still have a commonality, it is that we want to stop Thagirion.","TWN":"因為阻止塔基里翁是你和我之間為數不多的共同點之一。"},"stage":{"bg":"CORRIDOR_03","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그러니 꺼져요.","JPN":"ですから、消えてください。","ENG":"So, go away.","TWN":"所以快給我讓開。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그 여자의 꿍꿍이를 막든지, 깔끔하게 실패하고 죽어버리든지 하라고요.","JPN":"あの女の企みを止めるか、潔く失敗して死んでしまうのか、どちらかです。","ENG":"Go stop her scheming or die trying.","TWN":"要就去阻止她的陰謀，要就承認失敗乾脆地死去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아야야…","JPN":"いたた……","ENG":"Ouch...","TWN":"啊呀呀……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님. 저 방금 꼬리뼈 부딪힌 거 같아요.","JPN":"先輩。私、尾骨から落ちたようです。","ENG":"Mina, I think I broke my tailbone...","TWN":"前輩，我剛剛撞到尾椎了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그러게 떨어질 땐 허둥대지 말라고 했잖아.","JPN":"だから慎重に飛び降りろって言ったでしょ。","ENG":"I told you not to thrash around when falling.","TWN":"所以我說過墜下的時候不要亂動。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여긴 어디죠? 밖으로 나왔다고 생각했는데… 함선 안이 아니네요.","JPN":"ここはどこですか？　外に出たと思ったのに……艦船の中じゃないんですね。","ENG":"Where are we? I thought we finally made it out, but... this isn't the inside of the ship.","TWN":"這是哪裡？本來以為是到外面了……但這裡並不是艦船內。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"글쎄. 여기가 어딘진 모르겠지만…","JPN":"さぁ、ここがどこかはわからないけど……","ENG":"I dunno where we are, but...","TWN":"我也不知道……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저 녀석이 보이는 걸 보면, 제대로 온 것 같네.","JPN":"あいつが見えるということは、間違ってないということだね。","ENG":"I guess we're at the right place since I can see her.","TWN":"不過既然能看到那傢伙，說明我們應該是找對了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"거울 속 자신의 심상과 마주하게 되면 대부분은 자기자신과 충돌하게 되죠.","JPN":"鏡の中の自分の心と向き合うと、大抵の者は自分自身と衝突することになります。","ENG":"When one faces one's own image in the mirror, they usually clash with themselves.","TWN":"當你面對鏡中的自己時，通常會與自己產生衝突。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"클리파 차원에선 거울 속 상대가 실체를 갖게 되는 만큼, 대등한 자신과 끊임없이 싸우는 게 보통이지만…","JPN":"クリファ次元では鏡の中の相手が実体を持つので、対等な自分と絶え間なく戦うことになるのが普通ですが……","ENG":"As images in the mirror become real in the Qlipha Dimension, it is common to be in an endless battle with an equal self...","TWN":"在逆卡巴拉次元裡，鏡子裡的倒影也會實體化，最終會與自己陷入無止盡的戰鬥，但是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"여러분은 제법 일찍 빠져나오셨군요.","JPN":"みなさんはずいぶん早く脱出できましたね。","ENG":"However, you two made it out earlier than I anticipated.","TWN":"但是沒想到你們這麼快就逃出來了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"보통의 사람들과는 다르다는 증거이겠죠.","JPN":"普通の人とは違うという証でしょうか。","ENG":"Perhaps that proves that you are different from ordinary people.","TWN":"證明你們和大多數人不一樣。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 저 사람은…!","JPN":"あっ、あの人は……！","ENG":"Oh, that's...!","TWN":"喔，她……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"스완.","JPN":"スワン。","ENG":"Swan.","TWN":"史旺。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"당신이 벌이려는 짓을 여기서 멈춰주겠어.","JPN":"あなたの目論見を、ここで止めてやる。","ENG":"I've come to stop whatever it is you're trying to do.","TWN":"我要在這裡阻止你。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};